UPDATE event.events
SET  title             = #{title}
    ,description       = #{content}
    ,thumbnail_url     = #{thumbnailUrl}
    ,start_at          = #{eventStartDt}::date::timestamptz
    ,end_at            = #{eventEndDt}::date::timestamptz
    ,venue_name        = #{location}
    ,status            = #{status}
    ,updated_by        = #{uptUserSeq}
    ,updated_at        = CURRENT_TIMESTAMP
WHERE event_seq = #{eventSeq}
  AND deleted_at IS NULL
